/**
 * Get the scope map for a specific provider.
 */
export function getScopeMap(provider: string): ProviderScopeMap | undefined {
  return SCOPE_MAPS[provider];
}

/**
 * Get all available provider slugs.
 */
export function getProviderSlugs(): string[] {
  return Object.keys(SCOPE_MAPS);
}
